const src = $json.body || $json;
const now = new Date().toISOString();
return [{
  json: {
    ticket_id: String(src.ticket_id || src.id || `evt-${Date.now()}`),
    cliente: String(src.cliente || src.customer?.name || 'Cliente sem nome'),
    canal: String(src.canal || src.channel || 'outro'),
    mensagens: String(src.mensagens || src.message || src.description || ''),
    tecnico: String(src.tecnico || src.agent?.name || 'Integracao API'),
    data_evento: String(src.data_evento || src.created_at || now),
    metadata: {
      sourceSystem: String($env.SOURCE_SYSTEM || 'api'),
      sourceEntityId: String(src.event_id || src.id || Date.now()),
      tenantId: String($env.TENANT_ID || 'default'),
      ingestionId: String(src.ingestion_id || src.event_id || `ing-${Date.now()}`)
    }
  }
}];
